import{_ as l,H as e,f as a,i as t}from"./chunks/framework.Cvt1eIE0.js";const o="/quote/images/smtp.png",r="/quote/images/test_smtp.png",n="/quote/images/expiry.png",s="/quote/images/email/klaviyo.png",u="/quote/images/email/mailchimp.png",b=JSON.parse('{"title":"邮件与通知","description":"","frontmatter":{},"headers":[],"relativePath":"quote/emails-notifications.md","filePath":"quote/emails-notifications.md"}'),d={name:"quote/emails-notifications.md"};function h(c,i,p,g,m,P){return e(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="邮件与通知" tabindex="-1">邮件与通知 <a class="header-anchor" href="#邮件与通知" aria-label="Permalink to &quot;邮件与通知&quot;">​</a></h1><p>及时的沟通是报价成交的重要环节。Quote App 的邮件能力不只是 SMTP 发件配置，还包括：</p><ul><li>报价单提交后的通知邮件</li><li>报价状态更新后的通知邮件</li><li>报价被拒绝后的通知邮件</li><li>报价即将过期前的提醒邮件</li><li>第三方邮件营销平台集成</li></ul><h2 id="_1-自定义发件人-smtp-设置" tabindex="-1">1. 自定义发件人 (SMTP 设置) <a class="header-anchor" href="#_1-自定义发件人-smtp-设置" aria-label="Permalink to &quot;1. 自定义发件人 (SMTP 设置)&quot;">​</a></h2><p>默认情况下，系统使用应用代发邮件。为了提高品牌信任度，建议配置您自己的 SMTP。</p><h3 id="配置路径" tabindex="-1">配置路径 <a class="header-anchor" href="#配置路径" aria-label="Permalink to &quot;配置路径&quot;">​</a></h3><p><strong>Settings -&gt; SMTP</strong></p><p><img src="'+o+'" alt="SMTP 配置"></p><h3 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li>进入 <strong>Settings</strong>。</li><li>切换到 <strong>SMTP</strong> 标签页。</li><li>勾选 <strong>Use SMTP</strong>。</li><li>填写以下字段： <ul><li><strong>SMTP server</strong></li><li><strong>Encryption</strong></li><li><strong>Port</strong></li><li><strong>Username / Email address</strong></li><li><strong>Password</strong></li><li><strong>Send mail from email</strong></li><li><strong>Send mail from name</strong></li></ul></li><li>先点击 <strong>Connect</strong> 测试连接。</li><li>连接成功后再保存。</li></ol><p><img src="'+r+'" alt="SMTP 测试"></p><h3 id="常见端口示例" tabindex="-1">常见端口示例 <a class="header-anchor" href="#常见端口示例" aria-label="Permalink to &quot;常见端口示例&quot;">​</a></h3><ul><li>TLS 常用端口：<code>587</code></li><li>SSL 常用端口：<code>465</code></li></ul><h3 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h3><ul><li>如果您只是先测试前台报价流程，SMTP 可以稍后配置，不会影响按钮显示和提交报价。</li><li>但如果您希望客户真正收到通知邮件、提醒邮件或品牌化发件人，建议尽早完成 SMTP 设置。</li><li>通知邮件是否能发出，除了 SMTP 要正确以外，对应通知事件也必须处于启用状态。</li></ul><h2 id="_2-报价单通知邮件" tabindex="-1">2. 报价单通知邮件 <a class="header-anchor" href="#_2-报价单通知邮件" aria-label="Permalink to &quot;2. 报价单通知邮件&quot;">​</a></h2><p>Quote App 支持多种报价相关邮件，每一种都可以单独开启、关闭，并单独编辑主题与正文模板。</p><h3 id="配置路径-1" tabindex="-1">配置路径 <a class="header-anchor" href="#配置路径-1" aria-label="Permalink to &quot;配置路径&quot;">​</a></h3><p><strong>Settings -&gt; Notifications</strong></p><p>在该页面中，您可以选择不同的通知事件，并分别配置：</p><ul><li>是否启用该通知</li><li>邮件主题（Subject）</li><li>邮件正文（Body）</li></ul><h3 id="支持的通知事件" tabindex="-1">支持的通知事件 <a class="header-anchor" href="#支持的通知事件" aria-label="Permalink to &quot;支持的通知事件&quot;">​</a></h3><h4 id="quote-created" tabindex="-1">Quote created <a class="header-anchor" href="#quote-created" aria-label="Permalink to &quot;Quote created&quot;">​</a></h4><p>发送时机：</p><ul><li>客户在前台成功提交一笔新的报价请求时</li></ul><p>适用用途：</p><ul><li>告知客户系统已收到报价</li><li>作为自动确认邮件</li></ul><h4 id="quote-updated" tabindex="-1">Quote updated <a class="header-anchor" href="#quote-updated" aria-label="Permalink to &quot;Quote updated&quot;">​</a></h4><p>发送时机：</p><ul><li>商家在后台回复客户</li><li>商家更新报价内容，例如商品、价格、运费等</li></ul><p>适用用途：</p><ul><li>告知客户报价已被商家处理</li><li>提醒客户重新查看最新报价内容</li></ul><h4 id="quote-declined" tabindex="-1">Quote declined <a class="header-anchor" href="#quote-declined" aria-label="Permalink to &quot;Quote declined&quot;">​</a></h4><p>发送时机：</p><ul><li>商家在后台将报价单标记为拒绝 / declined 时</li></ul><p>适用用途：</p><ul><li>正式通知客户该报价未通过</li><li>引导客户联系商家或重新提交需求</li></ul><h4 id="quote-expiry-reminder" tabindex="-1">Quote expiry reminder <a class="header-anchor" href="#quote-expiry-reminder" aria-label="Permalink to &quot;Quote expiry reminder&quot;">​</a></h4><p>发送时机：</p><ul><li>报价单即将到期前，按照您设置的时间自动发送</li></ul><p>适用用途：</p><ul><li>提醒客户尽快接受或完成结账</li><li>提高报价转化率</li></ul><h2 id="_3-通知开关与状态更新说明" tabindex="-1">3. 通知开关与状态更新说明 <a class="header-anchor" href="#_3-通知开关与状态更新说明" aria-label="Permalink to &quot;3. 通知开关与状态更新说明&quot;">​</a></h2><p>这部分是最容易被忽略的。</p><p>邮件不是“只要配置 SMTP 就一定会自动发送”，而是需要同时满足：</p><ol><li>SMTP 已正确配置并启用</li><li>对应通知事件本身已启用</li></ol><p>例如：</p><ul><li>您配置好了 SMTP，但 <strong>Quote updated</strong> 没有启用，那么商家更新报价后客户不会收到邮件</li><li>您启用了 <strong>Quote declined</strong>，那么当报价状态被改成 <code>declined</code> 时，客户才会收到拒绝通知</li><li>您启用了 <strong>Quote expiry reminder</strong>，并设置了到期前提醒时间，系统才会在到期前自动发送提醒邮件</li></ul><h3 id="建议启用方式" tabindex="-1">建议启用方式 <a class="header-anchor" href="#建议启用方式" aria-label="Permalink to &quot;建议启用方式&quot;">​</a></h3><p>如果您想让客户完整接收到报价流程中的关键通知，通常建议至少启用：</p><ul><li><strong>Quote created</strong></li><li><strong>Quote updated</strong></li><li><strong>Quote declined</strong></li><li><strong>Quote expiry reminder</strong></li></ul><h2 id="_4-邮件模板编辑" tabindex="-1">4. 邮件模板编辑 <a class="header-anchor" href="#_4-邮件模板编辑" aria-label="Permalink to &quot;4. 邮件模板编辑&quot;">​</a></h2><p>在 <strong>Settings -&gt; Notifications</strong> 中，您可以针对每一种通知事件单独编辑模板。</p><p>可编辑内容包括：</p><ul><li><strong>Subject</strong>：邮件标题</li><li><strong>Body</strong>：邮件正文（HTML）</li></ul><h3 id="模板用途" tabindex="-1">模板用途 <a class="header-anchor" href="#模板用途" aria-label="Permalink to &quot;模板用途&quot;">​</a></h3><p>您可以用它来实现：</p><ul><li>品牌化语气</li><li>多语言内容</li><li>更明确的购买引导</li><li>售前或售后说明</li><li>客服联系方式展示</li></ul><h2 id="_6-自动化提醒-quote-expiry-reminder" tabindex="-1">6. 自动化提醒 (Quote Expiry Reminder) <a class="header-anchor" href="#_6-自动化提醒-quote-expiry-reminder" aria-label="Permalink to &quot;6. 自动化提醒 (Quote Expiry Reminder)&quot;">​</a></h2><p>您可以开启 <strong>报价单过期提醒</strong>，在报价单即将失效前自动发邮件给客户。</p><p><img src="'+n+'" alt="过期提醒"></p><h3 id="可配置内容" tabindex="-1">可配置内容 <a class="header-anchor" href="#可配置内容" aria-label="Permalink to &quot;可配置内容&quot;">​</a></h3><ul><li>是否启用提醒</li><li>到期前多久发送</li><li>使用哪一份提醒邮件模板</li></ul><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>商家已经send invioce，但客户还没有结账</li><li>商家希望在报价过期前再次提醒客户</li><li>需要提升报价转化率</li></ul><h2 id="_7-第三方集成" tabindex="-1">7. 第三方集成 <a class="header-anchor" href="#_7-第三方集成" aria-label="Permalink to &quot;7. 第三方集成&quot;">​</a></h2><p>除了直接发邮件外，您还可以把报价事件同步到第三方营销平台。</p><h3 id="klaviyo" tabindex="-1">Klaviyo <a class="header-anchor" href="#klaviyo" aria-label="Permalink to &quot;Klaviyo&quot;">​</a></h3><ul><li>同步报价单相关数据到 Klaviyo</li><li>可用于构建更复杂的自动化营销流程</li></ul><p><img src="'+s+'" alt="klaviyo"></p><h4 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h4><ul><li><p><strong>Public Key (Site ID)</strong> 作用：用于标识您的 Klaviyo 账户。</p></li><li><p><strong>Private API Key</strong> 作用：用于授权 Quote App 调用 Klaviyo API，写入客户资料和报价事件。</p></li></ul><h4 id="怎么获取" tabindex="-1">怎么获取 <a class="header-anchor" href="#怎么获取" aria-label="Permalink to &quot;怎么获取&quot;">​</a></h4><ul><li><p><strong>Public Key (Site ID)</strong> 获取位置：Klaviyo 后台 <strong>Settings -&gt; API Keys</strong> 说明：在本应用中，这个字段也显示为 <strong>Site ID</strong>。</p></li><li><p><strong>Private API Key</strong> 获取位置：Klaviyo 后台 <strong>Settings -&gt; API Keys</strong> 获取步骤：</p><ol><li>进入 <strong>Settings</strong></li><li>打开 <strong>API Keys</strong></li><li>点击创建新的 <strong>Private API Key</strong></li><li>创建完成后复制该 key 并保存</li></ol></li></ul><h4 id="补充说明" tabindex="-1">补充说明 <a class="header-anchor" href="#补充说明" aria-label="Permalink to &quot;补充说明&quot;">​</a></h4><ul><li>Private API Key 通常只会在创建时完整显示一次，建议立即保存。</li><li>启用后，系统会把报价流程中的关键事件同步到 Klaviyo，例如提交报价、更新报价、发送 invoice、完成报价、拒绝报价、过期报价等。</li><li>您可以在应用后台点击 <strong>Verify Keys</strong> 测试配置是否有效。</li></ul><h3 id="mailchimp" tabindex="-1">Mailchimp <a class="header-anchor" href="#mailchimp" aria-label="Permalink to &quot;Mailchimp&quot;">​</a></h3><ul><li>将提交报价的客户加入邮件列表</li><li>便于后续营销与客户跟进</li></ul><p><img src="'+u+'" alt="mailchimp"></p><h4 id="配置项说明-1" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明-1" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h4><ul><li><p><strong>API Key</strong> 作用：用于授权 Quote App 访问您的 Mailchimp 账户。</p></li><li><p><strong>Audience ID (List ID)</strong> 作用：指定要同步到哪一个 Audience，也就是哪个联系人列表。</p></li><li><p><strong>Server Prefix</strong> 作用：指定 Mailchimp API 所在的数据中心前缀，例如 <code>us1</code>、<code>us20</code>。</p></li></ul><h4 id="怎么获取-1" tabindex="-1">怎么获取 <a class="header-anchor" href="#怎么获取-1" aria-label="Permalink to &quot;怎么获取&quot;">​</a></h4><ul><li><p><strong>API Key</strong> 获取位置：Mailchimp 后台 <strong>Profile -&gt; Extras -&gt; API keys</strong> 获取步骤：</p><ol><li>点击右上角个人头像</li><li>进入 <strong>Profile</strong></li><li>打开 <strong>Extras -&gt; API keys</strong></li><li>点击创建或生成新的 API Key</li><li>复制生成后的 key 并保存</li></ol></li><li><p><strong>Audience ID (List ID)</strong> 获取位置：Mailchimp 后台 <strong>Audience -&gt; More options -&gt; Audience settings</strong> 说明：Audience ID 也常被称为 <strong>List ID</strong>。</p></li><li><p><strong>Server Prefix</strong> 获取方法： 直接查看 Mailchimp API Key 最后的后缀部分。</p><p>例如：</p><ul><li>API Key 为 <code>xxxxxx-us1</code>，则 Server Prefix 为 <code>us1</code></li><li>API Key 为 <code>xxxxxx-us20</code>，则 Server Prefix 为 <code>us20</code></li></ul></li></ul><h4 id="补充说明-1" tabindex="-1">补充说明 <a class="header-anchor" href="#补充说明-1" aria-label="Permalink to &quot;补充说明&quot;">​</a></h4><ul><li>Audience ID 必须对应您希望接收客户数据的目标 Audience。</li><li>API Key、Audience ID、Server Prefix 三者都需要正确，Mailchimp 才能成功同步。</li><li>配置完成后，建议在应用后台测试连接，确认配置无误。</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>SMTP 连接成功不代表所有通知事件都会发送，还需要单独启用对应事件</li><li>报价状态更新类邮件是否发送，取决于商家的实际操作是否触发了对应事件</li><li>建议至少测试一次：提交报价、更新报价、拒绝报价、到期提醒，确认邮件链路完整</li><li>修改模板后，建议先发送测试邮件或做真实流程测试，确认变量与版式显示正常</li></ul>',87)])])}const x=l(d,[["render",h]]);export{b as __pageData,x as default};
